/** * The contents of this file are subject to the license and copyright * detailed in the LICENSE and NOTICE files at the root of the source * tree and available online at * * http://www.dspace.org/license/ */package org.dspace.importer.external.viaf;import static org.dspace.importer.external.liveimportclient.service.LiveImportClientImpl.HEADER_PARAMETERS;import java.util.ArrayList;import java.util.Collection;import java.util.HashMap;import java.util.Iterator;import java.util.List;import java.util.Map;import java.util.concurrent.Callable;import java.util.stream.Collectors;import com.fasterxml.jackson.core.JsonProcessingException;import com.fasterxml.jackson.databind.JsonNode;import com.fasterxml.jackson.databind.ObjectMapper;import org.apache.commons.lang3.StringUtils;import org.apache.http.client.utils.URIBuilder;import org.apache.logging.log4j.LogManager;import org.apache.logging.log4j.Logger;import org.dspace.content.Item;import org.dspace.importer.external.datamodel.ImportRecord;import org.dspace.importer.external.datamodel.Query;import org.dspace.importer.external.exception.MetadataSourceException;import org.dspace.importer.external.liveimportclient.service.LiveImportClient;import org.dspace.importer.external.service.AbstractImportMetadataSourceService;import org.dspace.importer.external.service.components.QuerySource;import org.dspace.importer.external.viaf.contributors.ViafIdExtractor;import org.springframework.beans.factory.annotation.Autowired;/** * Implements a data source for querying VIAF (Virtual International Authority File) * It is a service that aggregates authority records from multiple national and international catalogues, * linking them into unified ‘clusters’ for a single entity (author, organisation, etc.). * * @author Mykhaylo Boychuk (mykhaylo.boychuk@4science.com) */public class ViafImportMetadataSourceServiceImpl        extends AbstractImportMetadataSourceService<String> implements QuerySource {    /**     * This class strips away any namespace prefix of fields inside the given JSON string.     * <pre>     *     {     *         "ns1:field":"Hello"     *     }     * </pre>     * becomes     * <pre>     *     {     *         "field":"Hello"     *     }     * </pre>     * <hr/>     * The JSON must be valid, i.e. the fields should have double quotes around them.     */    static class JSONNamespaceStripper {        public static String stripNamespaces(String jsonString) {            return jsonString.replaceAll("\"[^\"]*:([^\"]+)\"\\s*:", "\"$1\":");        }        public static Map<String, Object> stripNamespacesFromMap(Map<String, Object> map) {            Map<String, Object> result = new HashMap<>();            for (Map.Entry<String, Object> entry : map.entrySet()) {                String key = entry.getKey();                String cleanKey = key.contains(":") ? key.substring(key.lastIndexOf(':') + 1) : key;                Object value = entry.getValue();                if (value instanceof Map) {                    value = stripNamespacesFromMap((Map<String, Object>) value);                } else if (value instanceof List) {                    value = stripNamespacesFromList((List<Object>) value);                }                result.put(cleanKey, value);            }            return result;        }        private static List<Object> stripNamespacesFromList(List<Object> list) {            return list.stream()                       .map(item -> {                           if (item instanceof Map) {                               return stripNamespacesFromMap((Map<String, Object>) item);                           } else if (item instanceof List) {                               return stripNamespacesFromList((List<Object>) item);                           }                           return item;                       })                       .collect(Collectors.toList());        }    }    private final static Logger log = LogManager.getLogger(ViafImportMetadataSourceServiceImpl.class);    private final static String VIAF_SOURCE_NAME = "viaf";    private final static String JSON_TYPE = "application/json";    private final static String PATH_TO_RECORDS = "/searchRetrieveResponse/records/record";    private final static String RECORD_DATA = "/recordData";    private String url;    private String searchUrl;    private final static int timeout = 10000;    @Autowired    private LiveImportClient liveImportClient;    private ViafIdExtractor viafIdExtractor;    @Override    public void init() throws Exception { }    @Override    public String getImportSource() {        return VIAF_SOURCE_NAME;    }    @Override    public ImportRecord getRecord(String id) throws MetadataSourceException {        log.debug("Viaf search by id:{}", id);        if (StringUtils.isBlank(id)) {            return null;        }        return retry(new SearchByIdCallable(id));    }    @Override    public int getRecordsCount(String query) throws MetadataSourceException {        return retry(new CountByQueryCallable(query));    }    @Override    public int getRecordsCount(Query query) throws MetadataSourceException {        return retry(new CountByQueryCallable(query.toString()));    }    @Override    public Collection<ImportRecord> getRecords(String query, int start, int count) throws MetadataSourceException {        return retry(new SearchByQueryCallable(query, start, count));    }    @Override    public Collection<ImportRecord> getRecords(Query query) throws MetadataSourceException {        return retry(new SearchByQueryCallable(query));    }    @Override    public ImportRecord getRecord(Query query) throws MetadataSourceException {        return null;    }    @Override    public Collection<ImportRecord> findMatchingRecords(Query query) throws MetadataSourceException {        return retry(new SearchByQueryCallable(query));    }    @Override    public Collection<ImportRecord> findMatchingRecords(Item item) throws MetadataSourceException {        throw new UnsupportedOperationException("This method is not implemented for:" + VIAF_SOURCE_NAME);    }    private class SearchByIdCallable implements Callable<ImportRecord> {        private String recordId;        private SearchByIdCallable(String id) {            this.recordId = StringUtils.trim(id);        }        @Override        public ImportRecord call() throws Exception {            URIBuilder uriBuilder = new URIBuilder(url + this.recordId);            Map<String, Map<String, String>> params = new HashMap<String, Map<String,String>>();            params.put(HEADER_PARAMETERS, getHeaders());            String response = JSONNamespaceStripper.stripNamespaces(                liveImportClient.executeHttpGetRequest(timeout, uriBuilder.toString(),params)            );            return StringUtils.isNotBlank(response) ? transformSourceRecords(response) : null;        }    }    private class SearchByQueryCallable implements Callable<List<ImportRecord>> {        private String query;        private Integer start = 1;        private Integer count = 20;        private SearchByQueryCallable(String query, Integer start, Integer count) {            this.query = StringUtils.trim(query);            this.start = start > 0 ? start : this.start;            this.count = count > 0 ? count : this.count;        }        private SearchByQueryCallable(Query query) {            this.query = query.toString();        }        @Override        public List<ImportRecord> call() throws Exception {            List<ImportRecord> results = new ArrayList<>();            var queryParam = String.format("local.personalNames all \"%s\"", query);            log.info("VIAF: search call, query: {}" , queryParam);            URIBuilder uriBuilder = new URIBuilder(searchUrl);            uriBuilder.addParameter("query", queryParam);            uriBuilder.addParameter("startRecord", start.toString());            uriBuilder.addParameter("maximumRecords", count.toString());            Map<String, Map<String, String>> params = new HashMap<String, Map<String,String>>();            params.put(HEADER_PARAMETERS, getHeaders());            String response = JSONNamespaceStripper.stripNamespaces(                liveImportClient.executeHttpGetRequest(timeout, uriBuilder.toString()                , params)            );            if (StringUtils.isEmpty(response)) {                return results;            }            JsonNode jsonNode = convertStringJsonToJsonNode(response);            JsonNode recordNode = jsonNode.at(PATH_TO_RECORDS);            if (!recordNode.isArray()) {                return results;            }            Iterator<JsonNode> iterator = recordNode.iterator();            JsonNode node;            while (iterator.hasNext() && (node = iterator.next()) != null) {                JsonNode recordData = node.at(RECORD_DATA);                if (recordData != null && recordData.isObject()) {                    results.add(transformSourceRecords(recordData.toString()));                }            }            return results;        }    }    private class CountByQueryCallable implements Callable<Integer> {        private final static String PATH_TO_COUNT = "/searchRetrieveResponse/numberOfRecords/content";        private String query;        private CountByQueryCallable(String queryString) {            query = StringUtils.trim(queryString);        }        @Override        public Integer call() throws Exception {            var queryParam = String.format("local.personalNames all \"%s\"", query);            URIBuilder uriBuilder = new URIBuilder(searchUrl);            uriBuilder.addParameter("query", queryParam);            uriBuilder.addParameter("maximumRecords", "0");            Map<String, Map<String, String>> params = new HashMap<>();            params.put(HEADER_PARAMETERS, getHeaders());            String responseString = liveImportClient.executeHttpGetRequest(1000, uriBuilder.toString(), params);            if (StringUtils.isEmpty(responseString)) {                return 0;            }            JsonNode jsonNode = convertStringJsonToJsonNode(responseString);            return jsonNode.at(PATH_TO_COUNT).asInt();        }    }    protected JsonNode convertStringJsonToJsonNode(String json) {        ObjectMapper mapper = new ObjectMapper();        JsonNode body = null;        try {            body = mapper.readTree(json);        } catch (JsonProcessingException e) {            log.error("Unable to process json response. JSON: {}", json, e);        }        return body;    }    protected Map<String, String> getHeaders() {        Map<String, String> headers = new HashMap<String, String>();        headers.put("Accept", JSON_TYPE);        return headers;    }    public void setUrl(String url) {        this.url = url;    }    public void setSearchUrl(String searchUrl) {        this.searchUrl = searchUrl;    }    public void setViafIdExtractor(ViafIdExtractor viafIdExtractor) {        this.viafIdExtractor = viafIdExtractor;    }}